// ── QUESTION RENDERER ──────────────────────────────────────────────────────
function QuestionCard({ q, blockColor, myAnswers, onAnswer, totalParticipants, allAnswers, phase }) {
  const myAns = myAnswers[q.id] || [];
  const toggle = (opt) => {
    if (q.type === "vote" || q.type === "rating") {
      onAnswer(q.id, [opt]);
    } else {
      const has = myAns.includes(opt);
      onAnswer(q.id, has ? myAns.filter(x => x !== opt) : [...myAns, opt]);
    }
  };
  // Aggregate votes
  const counts = {};
  q.options.forEach(o => counts[o] = 0);
  if (allAnswers) {
    Object.values(allAnswers).forEach(userAns => {
      const ans = userAns[q.id] || [];
      ans.forEach(a => { if (counts[a] !== undefined) counts[a]++; });
    });
  }
  const maxCount = Math.max(1, ...Object.values(counts));
  const showResults = phase === "results";
  return (
    <div style={{ marginBottom: 20 }}>
      <p style={{ color: COLORS.text, fontSize: 16, fontWeight: 600, marginBottom: 14, fontFamily: "'Syne'" }}>{q.text}</p>
      <div style={{ display: "grid", gap: 10 }}>
        {q.options.map(opt => {
          const selected = myAns.includes(opt);
          const count = counts[opt] || 0;
          const pct = totalParticipants > 0 ? (count / totalParticipants) * 100 : 0;
          return (
            <button key={opt} onClick={() => toggle(opt)}
              style={{ background: selected ? blockColor + "22" : COLORS.surface, border: `1.5px solid ${selected ? blockColor : COLORS.border}`, borderRadius: 10, padding: "10px 14px", cursor: "pointer", textAlign: "left", color: COLORS.text, transition: "all .2s", fontFamily: "'DM Sans'", fontSize: 14 }}
              onMouseEnter={e => !selected && (e.currentTarget.style.borderColor = blockColor + "88")}
              onMouseLeave={e => !selected && (e.currentTarget.style.borderColor = COLORS.border)}>
              <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: showResults ? 6 : 0 }}>
                <span>{opt}</span>
                {showResults && <span style={{ color: blockColor, fontWeight: 700, fontSize: 13 }}>{count} voto{count !== 1 ? "s" : ""}</span>}
              </div>
              {showResults && <PulseBar pct={pct} color={blockColor} height={5} />}
            </button>
          );
        })}
      </div>
    </div>
  );
}

